#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;

int main() {
    vector<int> nums = {3, 7, 2, 9, 4, 7, 6, 1, 8};

    // find:
    auto it = find(nums.begin(), nums.end(), 9);
    if (it != nums.end())
        cout << "Found 9 at index: " << (it - nums.begin()) << endl;

    // find_if — first even number:
    auto even = find_if(nums.begin(), nums.end(), [](int n){ return n % 2 == 0; });
    if (even != nums.end())
        cout << "First even: " << *even << endl;

    // count_if:
    int evenCount = count_if(nums.begin(), nums.end(), [](int n){ return n % 2 == 0; });
    cout << "Even numbers: " << evenCount << endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <string>
#include <cctype>
using namespace std;

int main() {
    vector<int> nums = {1, 2, 3, 4, 5};
    vector<int> squares(nums.size());

    // Square each element:
    transform(nums.begin(), nums.end(), squares.begin(),
              [](int n){ return n * n; });
    for (int n : squares) cout << n << " ";
    cout << endl;

    // Uppercase a string:
    string s = "hello world";
    transform(s.begin(), s.end(), s.begin(), ::toupper);
    cout << s << endl;

    // Add two vectors element-wise:
    vector<int> a = {1, 2, 3};
    vector<int> b = {10, 20, 30};
    vector<int> c(3);
    transform(a.begin(), a.end(), b.begin(), c.begin(),
              [](int x, int y){ return x + y; });
    for (int n : c) cout << n << " ";
    cout << endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <string>
#include <functional>
using namespace std;

int main() {
    vector<int> nums = {1, 2, 3, 4, 5};

    int sum     = accumulate(nums.begin(), nums.end(), 0);
    int product = accumulate(nums.begin(), nums.end(), 1, multiplies<int>());
    cout << "Sum: " << sum << endl;
    cout << "Product: " << product << endl;

    // Join strings:
    vector<string> words = {"C++", "is", "amazing"};
    string joined = accumulate(words.begin() + 1, words.end(),
                               words[0],
                               [](string a, string b){ return a + " " + b; });
    cout << joined << endl;

    // Running average:
    double avg = static_cast<double>(sum) / nums.size();
    cout << "Average: " << avg << endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;

int main() {
    vector<int> scores = {85, 92, 78, 95, 88};
    vector<int> failing = {45, 72, 38, 55};

    cout << boolalpha;

    // All passing (>= 60)?
    cout << all_of(scores.begin(), scores.end(),
                   [](int s){ return s >= 60; }) << endl;  // true

    // Any perfect score?
    cout << any_of(scores.begin(), scores.end(),
                   [](int s){ return s == 100; }) << endl;  // false

    // None failing in scores?
    cout << none_of(scores.begin(), scores.end(),
                    [](int s){ return s < 60; }) << endl;   // true

    // Any passing in failing?
    cout << any_of(failing.begin(), failing.end(),
                   [](int s){ return s >= 60; }) << endl;   // true

    return 0;
}
